callGraph.callee:
entities.allIds
      .map((id) => {
        const entity = entities.byId[id] as {
          type?: string;
          modifiedAt?: string;
          props?: Record<string, unknown>;
          calculated?: Record<string, unknown>;
        } | undefined;

        if (!entity) {
          return `${id}:missing`;
        }

        return `${id}:${entity.type ?? 'unknown'}:${entity.modifiedAt ?? ''}:${JSON.stringify(
          entity.props ?? {}
        )}:${JSON.stringify(entity.calculated ?? {})}`;
      })
      .join

violations
    .map((violation) => {
      const fix = getObjectFix(violation.suggestedFix);
      if (!fix) {
        return null;
      }

      return {
        violationType: violation.type,
        severity: violation.severity,
        message: violation.message,
        fix,
      } as ValidationSuggestion;
    })
    .filter

CATEGORY_ORDER.map((category) => {
      const items = filteredItems.filter((item) => normalizeCategory(item) === category);
      const totalQty = items.reduce((sum, item) => sum + item.quantity, 0);
      const totalCost = hasCostData
        ? items.reduce(
            (sum, item) => sum + (costByItemNumber?.get(item.itemNumber)?.itemTotal ?? 0),
            0
          )
        : 0;
      return {
        category,
        label: CATEGORY_LABELS[category],
        items,
        count: items.length,
        totalQty,
        totalCost,
        primaryUnit: items[0]?.unit ?? '',
      };
    }).filter

new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format

ductComponents
    .filter((component) => {
      const nameMatches = normalizedName.length > 0 && component.name.trim().toLowerCase() === normalizedName;
      const shapeMatches = component.subtype ? component.subtype === entity.props.shape : true;
      const materialMatches = component.materials.some((material) => material.type === mappedMaterial);

      return nameMatches && shapeMatches && materialMatches;
    })
    .sort

ductComponents
    .filter((component) => {
      const shapeMatches = component.subtype ? component.subtype === entity.props.shape : true;
      return shapeMatches && component.materials.some((material) => material.type === mappedMaterial);
    })
    .sort

[...typedViolations]
      .sort((a, b) => {
        const severityOrder: Record<'error' | 'warning' | 'info', number> = {
          error: 0,
          warning: 1,
          info: 2,
        };
        const severityDiff = severityOrder[a.severity] - severityOrder[b.severity];
        if (severityDiff !== 0) {
          return severityDiff;
        }

        if (a.type !== b.type) {
          return a.type.localeCompare(b.type);
        }

        return a.message.localeCompare(b.message);
      })
      .map
